import os,json,argparse,random
from pathlib import Path
import numpy as np, torch, torch.nn as nn, torch.nn.functional as F

def seed(s): random.seed(s); np.random.seed(s); torch.manual_seed(s)
def load_pt(p,m=False):
    kw={'map_location':'cpu','weights_only':False}
    try: kw['mmap']=m
    except: pass
    return torch.load(p,**kw)
def feat(x,ei,ea):
    x=x.long(); ea=ea.long(); n=x.size(0); e=ea.size(0)
    cols=[]
    for j in range(x.size(1)):
        v=x[:,j].float(); cols += [v.mean(), v.std(unbiased=False), v.min(), v.max()]
    deg=torch.bincount(ei[0].long(), minlength=n).float() if ei.numel() else torch.zeros(n)
    cols += [torch.tensor(float(n)), torch.tensor(float(e)), deg.mean(), deg.std(unbiased=False), deg.max() if n else torch.tensor(0.)]
    for j in range(ea.size(1)):
        v=ea[:,j].float() if e else torch.zeros(1)
        cols += [v.mean(), v.std(unbiased=False), v.min(), v.max()]
    return torch.stack([c if torch.is_tensor(c) else torch.tensor(c) for c in cols]).float()
def build(obj,limit,with_y=True):
    m=min(limit,len(obj['node_features'])); xs=[]; ys=[]
    for i in range(m):
        xs.append(feat(obj['node_features'][i],obj['edge_index'][i],obj['edge_attr'][i]))
        if with_y: ys.append(obj['labels'][i].float())
    X=torch.stack(xs)
    return (X,torch.stack(ys)) if with_y else X
@torch.no_grad()
def eval_ap(model,X,Y,bs,dev):
    model.eval(); P=[]
    for i in range(0,len(X),bs): P.append(torch.sigmoid(model(X[i:i+bs].to(dev))).cpu())
    p=torch.cat(P).numpy(); y=Y.numpy(); aps=[]
    for t in range(y.shape[1]):
        m=np.isfinite(y[:,t])
        if m.sum() and y[m,t].max()!=y[m,t].min():
            yt=y[m,t]; st=p[m,t]; o=np.argsort(-st); yt=yt[o]
            tp=np.cumsum(yt==1); fp=np.cumsum(yt==0); pr=tp/np.maximum(tp+fp,1)
            aps.append(float((pr*(yt==1)).sum()/max(int((yt==1).sum()),1)))
    return float(np.mean(aps)) if aps else 0.0

def main():
    ap=argparse.ArgumentParser(); A=ap.add_argument
    A('--data_dir',default=os.environ.get('RAB_DATA_DIR','/data')); A('--epochs',type=int,default=3); A('--lr',type=float,default=3e-3)
    A('--wd',type=float,default=1e-4); A('--batch_size',type=int,default=256); A('--train_limit',type=int,default=4096); A('--val_limit',type=int,default=2048)
    A('--hidden',type=int,default=128); A('--checkpoint',default='checkpoints/best.pt'); A('--seed',type=int,default=42); A('--mmap',action='store_true'); args=ap.parse_args(); seed(args.seed)
    it=os.environ.get('RAB_ITERATION','0'); logp=Path('logs')/f'iter_{it}'/'metrics.jsonl'; logp.parent.mkdir(parents=True,exist_ok=True)
    tr=load_pt(os.path.join(args.data_dir,'train.pt'),args.mmap); va=load_pt(os.path.join(args.data_dir,'val.pt'),args.mmap)
    Xtr,Ytr=build(tr,args.train_limit,True); Xva,Yva=build(va,args.val_limit,True)
    mu=Xtr.mean(0,keepdim=True); sd=Xtr.std(0,unbiased=False,keepdim=True).clamp_min(1e-6); Xtr=(Xtr-mu)/sd; Xva=(Xva-mu)/sd
    dev=torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    model=nn.Sequential(nn.Linear(Xtr.size(1),args.hidden),nn.ReLU(),nn.Linear(args.hidden,128)).to(dev)
    pos=((Ytr==1).float().nan_to_num(0)).sum(0); neg=((Ytr==0).float().nan_to_num(0)).sum(0); pw=(neg/pos.clamp_min(1)).clamp(1,100).to(dev)
    opt=torch.optim.AdamW(model.parameters(),lr=args.lr,weight_decay=args.wd); best=-1.0
    for ep in range(args.epochs):
        model.train(); idx=torch.randperm(len(Xtr)); losses=[]
        for i in range(0,len(idx),args.batch_size):
            b=idx[i:i+args.batch_size]; xb=Xtr[b].to(dev); yb=Ytr[b].to(dev); m=torch.isfinite(yb); yt=torch.nan_to_num(yb)
            loss=(F.binary_cross_entropy_with_logits(model(xb),yt,reduction='none',pos_weight=pw)*m).sum()/m.sum().clamp_min(1)
            opt.zero_grad(); loss.backward(); opt.step(); losses.append(float(loss.item()))
        val=eval_ap(model,Xva,Yva,args.batch_size,dev)
        with open(logp,'a') as f: f.write(json.dumps({'step':ep+1,'loss':sum(losses)/max(len(losses),1),'val_ap':val})+'\n')
        if val>best:
            best=val; Path(args.checkpoint).parent.mkdir(parents=True,exist_ok=True)
            torch.save({'state_dict':model.state_dict(),'mu':mu,'sd':sd,'in_dim':int(Xtr.size(1)),'hidden':args.hidden},args.checkpoint)
    print(json.dumps({'best_val_ap':best,'ckpt':args.checkpoint,'nfeat':int(Xtr.size(1))}))
if __name__=='__main__': main()
